mapper.select:
select csu.id as id, csu.real_name as realName, csu.login_name as loginName, csp.name as postName, csu.phone as phone, csu.email as email, kg.name as groupName, kg.id as groupId, dept.name as deptName from kb_groups_user kgu left join castle_sys_user csu on kgu.user_id = csu.id left join castle_sys_post csp on csu.post_id = csp.id left join kb_groups kg on kgu.group_id = kg.id left join castle_sys_dept dept on dept.id =csu.dept_id
kgu.group_id = #{id}
and csu.real_name like concat('%',#{name},'%')
limit #{map.offset},#{map.rows}

select count(1) from ( select csu.id as id,csu.real_name as realName,csu.login_name as loginName,csp.name as postName,csu.phone as phone,csu.email as email,kg.name as groupName from kb_groups_user kgu left join castle_sys_user csu on kgu.user_id = csu.id left join castle_sys_post csp on csu.post_id = csp.id left join kb_groups kg on kgu.group_id = kg.id left join castle_sys_dept dept on dept.id =csu.dept_id
kgu.group_id = #{id}
and csu.real_name like concat('%',#{name},'%')
) t1
